import React, { useEffect, useMemo, useRef, useState } from 'react';
import { PUZZLES, PUZZLE_OPTIONS } from './data/puzzles';
import {
  areAdjacent,
  canAddBridge,
  checkConnectivity,
  computeCurrentCounts,
  isVictory,
  makeBridgeKey
} from './utils/hashiLogic';

const GRID = 40;
const SVG_W = 800;
const SVG_H = 600;

function px(n) {
  return n * GRID;
}

function parseBridgeKey(key) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  return { x1, y1, x2, y2 };
}

function getIslandById(islands, id) {
  return islands.find((i) => i.id === id) || null;
}

function getNeighbors(islands, from) {
  const nbs = [];
  for (const to of islands) {
    if (to.id === from.id) continue;
    if (areAdjacent(islands, from, to)) nbs.push(to);
  }
  return nbs;
}

function pickInDirection(islands, from, dir) {
  // Choose the nearest adjacent island in that cardinal direction (not just any island).
  let best = null;
  for (const to of islands) {
    if (to.id === from.id) continue;

    if (dir === 'left' && to.y === from.y && to.x < from.x) {
      if (!areAdjacent(islands, from, to)) continue;
      if (!best || to.x > best.x) best = to;
    }
    if (dir === 'right' && to.y === from.y && to.x > from.x) {
      if (!areAdjacent(islands, from, to)) continue;
      if (!best || to.x < best.x) best = to;
    }
    if (dir === 'up' && to.x === from.x && to.y < from.y) {
      if (!areAdjacent(islands, from, to)) continue;
      if (!best || to.y > best.y) best = to;
    }
    if (dir === 'down' && to.x === from.x && to.y > from.y) {
      if (!areAdjacent(islands, from, to)) continue;
      if (!best || to.y < best.y) best = to;
    }
  }
  return best;
}

function applyToggleBridge(islands, bridges, from, to) {
  // cycles none -> single -> double -> none, returns {bridges,nextError}
  const key = makeBridgeKey(from, to);
  const existing = bridges.get(key) ?? 0;
  const desired = existing === 0 ? 1 : existing === 1 ? 2 : 0;

  // Build a new map and validate stepwise when increasing.
  const next = new Map(bridges);

  if (desired === 0) {
    next.delete(key);
    return { bridges: next, error: null };
  }

  const delta = desired - existing; // 1 (0->1 or 1->2)
  const check = canAddBridge(islands, bridges, from, to, delta);
  if (!check.valid) {
    return { bridges, error: check.error };
  }

  next.set(key, desired);
  return { bridges: next, error: null };
}

export default function App() {
  const [puzzleKey, setPuzzleKey] = useState('Easy');
  const islands = useMemo(() => PUZZLES[puzzleKey].islands, [puzzleKey]);

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedId, setSelectedId] = useState(null);
  const [cursorId, setCursorId] = useState(0);
  const [error, setError] = useState(null);
  const [victory, setVictory] = useState(false);

  const islandsRef = useRef(islands);
  const bridgesRef = useRef(bridges);
  const selectedRef = useRef(selectedId);
  const cursorRef = useRef(cursorId);

  useEffect(() => {
    islandsRef.current = islands;
  }, [islands]);
  useEffect(() => {
    bridgesRef.current = bridges;
  }, [bridges]);
  useEffect(() => {
    selectedRef.current = selectedId;
  }, [selectedId]);
  useEffect(() => {
    cursorRef.current = cursorId;
  }, [cursorId]);

  // Recompute victory on changes.
  useEffect(() => {
    setVictory(isVictory(islands, bridges));
  }, [islands, bridges]);

  // Keyboard controls: global listener, cursor starts at island 0 and resets on puzzle change.
  useEffect(() => {
    function onKeyDown(e) {
      const curIslands = islandsRef.current;
      const curBridges = bridgesRef.current;
      const curCursorId = cursorRef.current;
      const curSelectedId = selectedRef.current;

      const cursorIsland = getIslandById(curIslands, curCursorId) || curIslands[0];
      if (!cursorIsland) return;

      if (e.key === 'Escape') {
        setSelectedId(null);
        setError(null);
        return;
      }

      const dirMap = {
        ArrowLeft: 'left',
        ArrowRight: 'right',
        ArrowUp: 'up',
        ArrowDown: 'down'
      };
      if (dirMap[e.key]) {
        const next = pickInDirection(curIslands, cursorIsland, dirMap[e.key]);
        if (next) setCursorId(next.id);
        return;
      }

      if (e.key === 'Enter') {
        if (curSelectedId == null) {
          setSelectedId(cursorIsland.id);
          setError(null);
          return;
        }

        const from = getIslandById(curIslands, curSelectedId);
        const to = cursorIsland;

        if (!from || !to || from.id === to.id) {
          setSelectedId(null);
          setError(null);
          return;
        }

        const { bridges: nextBridges, error: nextError } = applyToggleBridge(curIslands, curBridges, from, to);
        if (nextError) {
          setError(nextError);
          setSelectedId(null); // reset in-progress selection on error
          setCursorId(0);
          return;
        }

        setBridges(nextBridges);
        setError(null);
        setSelectedId(null);
        setCursorId(0);
      }
    }

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, []);

  function resetAll() {
    setBridges(new Map());
    setSelectedId(null);
    setError(null);
    setVictory(false);
    setCursorId(0);
  }

  function onChangePuzzle(e) {
    const nextKey = e.target.value;
    // Reset everything in the same update sequence (bridges + selection/error/victory/cursor)
    setPuzzleKey(nextKey);
    setBridges(new Map());
    setSelectedId(null);
    setError(null);
    setVictory(false);
    setCursorId(0);
  }

  function handleIslandClick(island) {
    if (selectedId == null) {
      setSelectedId(island.id);
      setCursorId(island.id);
      setError(null);
      return;
    }

    if (selectedId === island.id) {
      // Clicking same island again just keeps selection (or could deselect). We'll deselect.
      setSelectedId(null);
      setError(null);
      setCursorId(0);
      return;
    }

    const from = getIslandById(islands, selectedId);
    const to = island;

    const { bridges: nextBridges, error: nextError } = applyToggleBridge(islands, bridges, from, to);
    if (nextError) {
      setError(nextError);
      setSelectedId(null); // critical: reset selection so next click starts a fresh pair
      setCursorId(0);
      return;
    }

    setBridges(nextBridges);
    setError(null); // remove the element moment a valid toggle executes
    setSelectedId(null);
    setCursorId(0);
  }

  function clearBridgePairByKey(key) {
    // Removing either line in a double clears the pair.
    setBridges((prev) => {
      const next = new Map(prev);
      next.delete(key);
      return next;
    });
    setError(null);
    setSelectedId(null);
    setCursorId(0);
  }

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);

  const bridgeLines = [];
  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseBridgeKey(key);
    const isH = y1 === y2;

    const p1 = { x: px(x1), y: px(y1) };
    const p2 = { x: px(x2), y: px(y2) };

    const dx = isH ? 0 : 6; // offset for double
    const dy = isH ? 6 : 0;

    const mkHandlers = () => ({
      onClick: (e) => {
        if (e.ctrlKey) {
          clearBridgePairByKey(key);
        }
      },
      onContextMenu: (e) => {
        e.preventDefault();
        clearBridgePairByKey(key);
      }
    });

    if (n === 1) {
      bridgeLines.push(
        <line
          key={key}
          x1={p1.x}
          y1={p1.y}
          x2={p2.x}
          y2={p2.y}
          stroke="#0f0"
          strokeWidth={4}
          {...mkHandlers()}
        />
      );
    } else if (n === 2) {
      bridgeLines.push(
        <line
          key={`${key}-a`}
          x1={p1.x + dx}
          y1={p1.y + dy}
          x2={p2.x + dx}
          y2={p2.y + dy}
          stroke="#0f0"
          strokeWidth={4}
          {...mkHandlers()}
        />
      );
      bridgeLines.push(
        <line
          key={`${key}-b`}
          x1={p1.x - dx}
          y1={p1.y - dy}
          x2={p2.x - dx}
          y2={p2.y - dy}
          stroke="#0f0"
          strokeWidth={4}
          {...mkHandlers()}
        />
      );
    }
  }

  const cursorIsland = getIslandById(islands, cursorId) || islands[0];
  const cursorX = cursorIsland ? px(cursorIsland.x) : 0;
  const cursorY = cursorIsland ? px(cursorIsland.y) : 0;

  return (
    <div style={{ position: 'relative' }}>
      <div style={{ padding: 8, display: 'flex', gap: 12, alignItems: 'center' }}>
        <label>
          Puzzle:{' '}
          <select value={puzzleKey} onChange={onChangePuzzle} style={{ background: 'black', color: '#0f0', border: '1px solid #0f0', fontFamily: 'monospace' }}>
            {PUZZLE_OPTIONS.map((o) => (
              <option key={o.key} value={o.key}>
                {o.label}
              </option>
            ))}
          </select>
        </label>
        <button
          onClick={resetAll}
          style={{ background: 'black', color: '#0f0', border: '1px solid #0f0', fontFamily: 'monospace' }}
        >
          Reset
        </button>
        <div style={{ fontSize: 12 }}>
          {checkConnectivity(islands, bridges) ? 'Connected' : 'Not connected'}
        </div>
      </div>

      {error ? <div className="error-message" style={{ paddingLeft: 8, paddingBottom: 6 }}>
        {error}
      </div> : null}

      {victory ? <div className="victory-banner" style={{ paddingLeft: 8, paddingBottom: 6 }}>
        SOLVED!
      </div> : null}

      <svg
        width={SVG_W}
        height={SVG_H}
        style={{ display: 'block' }}
      >
        {/* Bridges */}
        {bridgeLines}

        {/* Cursor (non-circle) */}
        {cursorIsland ? (
          <rect
            x={cursorX - 18}
            y={cursorY - 18}
            width={36}
            height={36}
            fill="none"
            stroke={selectedId != null ? '#0f0' : '#0f0'}
            strokeWidth={2}
            strokeDasharray={selectedId != null ? '0' : '6 4'}
          />
        ) : null}

        {/* Islands */}
        {islands.map((isl) => {
          const cx = px(isl.x);
          const cy = px(isl.y);
          const isSelected = selectedId === isl.id;
          const cur = counts.get(isl.id) ?? 0;

          return (
            <g key={isl.id}>
              <circle
                cx={cx}
                cy={cy}
                r={16}
                fill="black"
                stroke={isSelected ? '#0f0' : '#0f0'}
                strokeWidth={2}
                onClick={() => handleIslandClick(isl)}
              />
              <text
                x={cx}
                y={cy + 5}
                textAnchor="middle"
                fontFamily="monospace"
                fontSize="14"
                fill="#0f0"
                style={{ userSelect: 'none', pointerEvents: 'none' }}
              >
                {isl.value}
              </text>
              {/* tiny current count indicator */}
              <text
                x={cx}
                y={cy + 28}
                textAnchor="middle"
                fontFamily="monospace"
                fontSize="10"
                fill="#0f0"
                style={{ userSelect: 'none', pointerEvents: 'none' }}
              >
                {cur}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}
