    (p.x === q1.x && p.y === q1.y) || (p.x === q2.x && p.y === q2.y);

  if (isEndpoint(ip, h.p1, h.p2)) return false;
  if (isEndpoint(ip, v.p1, v.p2)) return false;

  return true;
}

export function bridgesWouldCross(islands, bridges, from, to) {
  const a1 = { x: from.x, y: from.y };
  const a2 = { x: to.x, y: to.y };
  for (const [key, count] of bridges.entries()) {
    if (!count) continue;
    const [x1, y1, x2, y2] = key.split(',').map(Number);
    const b1 = { x: x1, y: y1 };
    const b2 = { x: x2, y: y2 };

    // If same pair, ignore (adding within same segment never "crosses" itself).
    const same = (a1.x === b1.x && a1.y === b1.y && a2.x === b2.x && a2.y === b2.y) ||
      (a1.x === b2.x && a1.y === b2.y && a2.x === b1.x && a2.y === b1.y);
    if (same) continue;

    // Sharing endpoints is allowed.
    const sharesEndpoint =
      (a1.x === b1.x && a1.y === b1.y) ||
      (a1.x === b2.x && a1.y === b2.y) ||
      (a2.x === b1.x && a2.y === b1.y) ||
      (a2.x === b2.x && a2.y === b2.y);
    if (sharesEndpoint) continue;

    if (segmentsCross(a1, a2, b1, b2)) return true;
  }
  return false;
}

export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const isl of islands) counts.set(isl.id, 0);

  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const [x1, y1, x2, y2] = key.split(',').map(Number);

    const a = islands.find((i) => i.x === x1 && i.y === y1);
    const b = islands.find((i) => i.x === x2 && i.y === y2);
    if (!a || !b) continue;

    counts.set(a.id, (counts.get(a.id) ?? 0) + n);
    counts.set(b.id, (counts.get(b.id) ?? 0) + n);
  }

  return counts;
}

export function canAddBridge(islands, bridges, from, to, delta) {
  if (!from || !to) return { valid: false, error: 'Invalid islands' };
  if (from.id === to.id) return { valid: false, error: 'Cannot connect island to itself' };
  if (!areAdjacent(islands, from, to)) return { valid: false, error: 'Cannot connect non-adjacent islands' };

  const key = makeBridgeKey(from, to);
  const existing = bridges.get(key) ?? 0;
  const next = existing + delta;

  if (next > 2) return { valid: false, error: 'Max 2 bridges per pair' };
  if (next < 0) return { valid: false, error: 'Invalid bridge count' };

  // Crossing check only needed if we are increasing above existing.
  if (delta > 0 && next > existing) {
    if (bridgesWouldCross(islands, bridges, from, to)) {
      return { valid: false, error: 'Bridges would cross' };
    }
  }

  // Capacity check: islands cannot exceed required value
  const counts = computeCurrentCounts(islands, bridges);
  const fromCount = counts.get(from.id) ?? 0;
  const toCount = counts.get(to.id) ?? 0;

  if (fromCount + delta > from.value || toCount + delta > to.value) {
    return { valid: false, error: 'Island would exceed its number' };
  }

  return { valid: true, error: null };
}

export function checkConnectivity(islands, bridges) {
  if (islands.length === 0) return true;

  const byCoord = new Map();
  for (const isl of islands) byCoord.set(`${isl.x},${isl.y}`, isl);

  const adj = new Map();
  for (const isl of islands) adj.set(isl.id, []);

  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const [x1, y1, x2, y2] = key.split(',').map(Number);
    const a = byCoord.get(`${x1},${y1}`);
    const b = byCoord.get(`${x2},${y2}`);
    if (!a || !b) continue;
    adj.get(a.id).push(b.id);
    adj.get(b.id).push(a.id);
  }

  const seen = new Set();
  const stack = [islands[0].id];
  seen.add(islands[0].id);
  while (stack.length) {
    const cur = stack.pop();
    for (const nb of adj.get(cur) || []) {
      if (!seen.has(nb)) {
        seen.add(nb);
        stack.push(nb);
      }
    }
  }

  return seen.size === islands.length;
}

export function isVictory(islands, bridges) {
  // no crossings
  for (const [keyA, nA] of bridges.entries()) {
    if (!nA) continue;
    const [ax1, ay1, ax2, ay2] = keyA.split(',').map(Number);
    const a1 = { x: ax1, y: ay1 };
    const a2 = { x: ax2, y: ay2 };

    for (const [keyB, nB] of bridges.entries()) {
      if (!nB) continue;
      if (keyA === keyB) continue;
      const [bx1, by1, bx2, by2] = keyB.split(',').map(Number);
      const b1 = { x: bx1, y: by1 };
      const b2 = { x: bx2, y: by2 };
      if (segmentsCross(a1, a2, b1, b2)) return false;
    }
  }

  const counts = computeCurrentCounts(islands, bridges);
  for (const isl of islands) {
    if ((counts.get(isl.id) ?? 0) !== isl.value) return false;
  }

  if (!checkConnectivity(islands, bridges)) return false;

  return true;
}
